// Worker bindings (DB, MEDIA, EMAIL, ASSETS) and vars (APP_ORIGIN, EMAIL_FROM,
// …) are generated by `wrangler types` into worker-configuration.d.ts as
// Cloudflare.Env — regenerate with `npm run cf-typegen` after editing
// wrangler.jsonc. Only request-scoped locals live here.
declare namespace App {
  interface Locals {
    user: import('./lib/types').SessionUser | null;
    // narrowed in later slice
    locale: string;
    theme: string;
  }
}
